var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"…예전에 레이 선배가 말했지? ","JPN":"……前にレイ先輩は言ったよね？ ","ENG":"...You told me before.","TWN":"……以前雷伊前輩說過吧？"},"stage":{"bg":"THRONE_VOID","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_29-2"},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"때로는 진실을 모르는 채로 남아 있는 편이 낫다고.","JPN":"時には真実を知らないままの方がいいこともあるって。","ENG":"That sometimes I'll be happier not knowing things.","TWN":"有時候不知道真相反而更好。"},"stage":{"bg":"THRONE_VOID","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_30"},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그래도 나는 확인해야겠어.","JPN":"それでも私は知りたい。","ENG":"But I still need to know.","TWN":"但我還是想要知道，想要去了解。"},"stage":{"bg":"THRONE_VOID","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_31"},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"선배 말처럼 괴로울 수도 있겠지만……!","JPN":"先輩の言う通り、辛いことかもしれない……！","ENG":"It might be painful, like you said...!","TWN":"雖然可能會像前輩說的那樣痛苦……！"},"stage":{"bg":"THRONE_VOID","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_32"},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"감당하기 힘들지도 모르지만……!","JPN":"耐えがたいものかもしれない……！","ENG":"It might be hard for me to bear...!","TWN":"或許還很難承受……！"},"stage":{"bg":"THRONE_VOID","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_33"},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"아무것도 모르는 채로 사람들을 잃어 버리는 건 지긋지긋하다고!!","JPN":"でも何も知らないまま人を失うのはもう、うんざりなの！！","ENG":"But I am sick and tired of losing people without knowing why!","TWN":"但是我已經厭倦在一無所知的情況下失去誰了！！"},"stage":{"bg":"THRONE_VOID","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_34"},{"id":"L12_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":" ……그게 운명이란 겁니다!","JPN":" ……それが運命なんです！","ENG":"...That's how fate works!","TWN":"……這就是命運！"},"stage":{"bg":"THRONE_VOID","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":" 전하도 알렌도, 루크레시아도, 샬롯도!","JPN":" 殿下もアレンも、ルクレシアも、シャーロットも！","ENG":"His Highness, Allen, Lucrecia, and Carlota!","TWN":"殿下，艾倫，露可蕾西亞和夏洛特！"},"stage":{"bg":"THRONE_VOID","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":" 좋아서 떠나 보낸 사람은 아무도 없습니다!","JPN":" 失ってもいい人なんて一人もいなかった！","ENG":"Not a single person was lost because I wanted them to be!","TWN":"沒有一個是我願意送走的！"},"stage":{"bg":"THRONE_VOID","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"나도 한때는 그렇게 생각했어.","JPN":"私も前はそう思っていた。","ENG":"I used to think the same way.","TWN":"我也曾經那樣想過。"},"stage":{"bg":"THRONE_VOID","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_35"},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"죽은 친구도.","JPN":"死んだ友達も。","ENG":"My dead friend.","TWN":"死去的朋友。"},"stage":{"bg":"MAINSTREAM_320010","bgm":"THEMA_SEASON2","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_36"},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"쓰러져 버린 언니도.","JPN":"倒れた姉さんも。","ENG":"My fallen sister.","TWN":"病倒的姊姊。"},"stage":{"bg":"MAINSTREAM_320010","bgm":"THEMA_SEASON2","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_37"},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"망가진 내 인생도…","JPN":"壊れてしまった私の人生も……","ENG":"My broken life...","TWN":"毀掉我的人生……"},"stage":{"bg":"MAINSTREAM_344010","bgm":"THEMA_SEASON2","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_38"},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그저 운명일 뿐이라고.","JPN":"ただの運命だって。","ENG":"Perhaps it's just fate.","TWN":"全都是命運。"},"stage":{"bg":"MAINSTREAM_344010","bgm":"THEMA_SEASON2","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_39"},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"하지만 그 운명에 맞서는 사람들이 있었어.","JPN":"でもその運命に立ち向かう人たちがいた。","ENG":"But there were people who were fighting against that.","TWN":"但是有的人在對抗命運。"},"stage":{"bg":"MAINSTREAM_344010","bgm":"THEMA_SEASON2","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_40"},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"소대장도,","JPN":"小隊長も、","ENG":"Commander,","TWN":"小隊長，"},"stage":{"bg":"MAINSTREAM_7130013","bgm":"THEMA_SEASON2","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_41"},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"주시윤 선배도,","JPN":"アキヤマ先輩も、","ENG":"Joo Shiyoon,","TWN":"周時雲前輩，"},"stage":{"bg":"MAINSTREAM_7100012","bgm":"THEMA_SEASON2","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_42"},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"서윤도, 부사장님도……","JPN":"シズカも、副社長も……","ENG":"Seo Yoon, and even the Vice President...","TWN":"徐芸，副總……"},"stage":{"bg":"BLACK","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_43"},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"모두가, 전력을 다해서 버텨내고 있었어.","JPN":"みんなが、全力で耐え忍んでいた。","ENG":"Everyone was trying their very best to fight.","TWN":"所有人，都在盡全力堅持著。"},"stage":{"bg":"BLACK","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_44"},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그리고 그들이 버텨냈기에… 내가 여기에 서 있어.","JPN":"そして彼らが耐えてくれたからこそ……私はここに立っている。","ENG":"And because they did so... It brought me here.","TWN":"因為他們堅持下來了……我才能站在這裡。"},"stage":{"bg":"THRONE_VOID","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_45"},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"레이 선배, 당신의 앞에 맞서고 있는 거야.","JPN":"レイ先輩、あなたの前に立っているんだ。","ENG":"It brought me to you, Ray.","TWN":"站在雷伊前輩你的面前。"},"stage":{"bg":"THRONE_VOID","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_46"},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그러니까 이제는… 내가 그들을 위해 버텨내겠어.","JPN":"だから今度は…私がみんなのために耐えてみせる。","ENG":"So now... I will fight for them.","TWN":"所以現在……我要為了他們而堅持。"},"stage":{"bg":"THRONE_VOID","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_47"},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그 어떤 운명과… 숙명이 있더라도!","JPN":"どんな運命や…宿命があっても！","ENG":"No matter what fate... or destiny lies!","TWN":"不管是什麼命運……和宿命！"},"stage":{"bg":"THRONE_VOID","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_48"},{"id":"L40_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":"쉽게 떠들지 마세요!","JPN":"簡単に言わないでください！","ENG":"You don't know what you're talking about!","TWN":"你根本不知道你在說些什麼！"},"stage":{"bg":"THRONE_VOID","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":"대적자가 무엇인지, 구원자가 무엇인지 압니까?","JPN":"敵対者が何なのか、救世主が何なのか、あなたは知っているんですか？","ENG":"Have you any idea what it means to be an Antagonist, or the Savior?","TWN":"你知道敵對者是什麼，救贖者是什麼嗎？"},"stage":{"bg":"THRONE_VOID","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":"의무가 무엇인지, 맹세가 무엇인지 아느냐고요!","JPN":"義務が何なのか、誓いが何なのか知っているのかって聞いているんです！","ENG":"What your mission is, what your vows are!","TWN":"你知道他們的義務是什麼，誓言是什麼嗎！"},"stage":{"bg":"THRONE_VOID","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":"저에게는 이제, 이것밖에 남지 않았단 말입니다!!","JPN":"僕にはもう、これしか残っていなんです！！","ENG":"Those are all I have left!","TWN":"對我來說，如今這就是我的全部了！！"},"stage":{"bg":"THRONE_VOID","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"하지만 선배.","JPN":"でも先輩。","ENG":"But Ray.","TWN":"但是前輩。"},"stage":{"bg":"THRONE_VOID","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_49"},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그러는 선배도 지금, 발버둥치고 있잖아?","JPN":"そういう先輩だって今、もがいているんでしょ？","ENG":"You're still fighting now, aren't you?","TWN":"那樣的前輩，現在也在掙扎不是嗎？"},"stage":{"bg":"THRONE_VOID","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_50"},{"id":"L47_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":"뭐… 라고요?","JPN":"なん……ですって？","ENG":"What...?","TWN":"你……說什麼？"},"stage":{"bg":"THRONE_VOID","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":" 내가 도와줄게.","JPN":" 私が助けるよ。","ENG":"I'll help you.","TWN":" 我來幫你。"},"stage":{"bg":"THRONE_VOID","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_51"},{"id":"L49_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"선배도… 운명에서 버틸 수 있게!","JPN":"先輩も……運命に立ち向かえるように！","ENG":"So that... you can stand up against fate!","TWN":"讓前輩……也能在命運中堅持下去！"},"stage":{"bg":"THRONE_VOID","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_52"}]`);export{e as default};